//! Quality corpus — base-completion probes asserted by TEXT, not magic ids.
//!
//! Each probe is a known prompt whose correct next token the cached dense Qwen
//! coder knot must produce as its *argmax* (greedy decode). The probe is driven
//! by the prebuilt `paris-probe-rknot` (the dense `lm_head` over a real CPU
//! forward), and the predicted token is then DECODED back to a string via the
//! Qwen tokenizer so the assertion reads as text — "the model said \" Paris\""
//! — instead of an opaque "token 12095". The decoded text is the source of
//! truth; the token id is shown alongside for debugging.
//!
//! Every probe here was empirically verified to argmax cleanly on
//! `~/.edgework/models/qwen-coder-7b.knot`; a probe that does not argmax to its
//! expected word does not belong in this file (we never lower the bar).
//!
//! Heavy + gated: each probe is a ~25s 7B CPU forward, so this SKIPS (passes)
//! unless the cached dense knot and the prebuilt probe binary are present, and
//! the *text* assertion further requires the Qwen tokenizer (tsx + the
//! tokenizer gguf). With nothing present, plain `cargo test` stays light.
//! Enable by having all of:
//!   - a dense Qwen `.knot` ($MONSTER_SWARM_QWEN_KNOT, else
//!     ~/.edgework/models/qwen-coder-7b.knot),
//!   - the prebuilt probe ($MONSTER_SWARM_PROBE_BIN, else
//!     ../distributed-inference/target/release/paris-probe-rknot),
//!   - tsx + the tokenizer gguf for the text decode
//!     ($MONSTER_SWARM_TSX / $MONSTER_SWARM_TOKENIZER_GGUF /
//!      $MONSTER_SWARM_TOKENIZER_TS, with the documented defaults).

use std::path::PathBuf;
use std::process::Command;

/// One verified base-completion probe.
struct Probe {
    /// Human-readable prompt (documentation only — the ids are authoritative).
    prompt: &'static str,
    /// Qwen2.5 token ids for `prompt` (computed with the Qwen tokenizer).
    tokens: &'static [usize],
    /// The word the model must complete with (what the predicted token decodes
    /// to). This is the assertion the test reads as text.
    expected_word: &'static str,
    /// The token id `expected_word` encodes to — the id `paris-probe-rknot`
    /// is told to expect, kept so a decode-less run still has a hard target.
    expected_id: u64,
}

/// The verified corpus. Each entry argmaxes cleanly on the cached coder knot.
const CORPUS: &[Probe] = &[
    // "The capital of France is" -> " Paris"
    Probe {
        prompt: "The capital of France is",
        tokens: &[785, 6722, 315, 9625, 374],
        expected_word: " Paris",
        expected_id: 12095,
    },
    // "The capital of Japan is" -> " Tokyo"
    Probe {
        prompt: "The capital of Japan is",
        tokens: &[785, 6722, 315, 6323, 374],
        expected_word: " Tokyo",
        expected_id: 26194,
    },
    // "2 + 2 = " (trailing space) -> "4". The bare "2 + 2 =" argmaxes to a
    // space, so the prompt carries the space and the next token is the digit.
    Probe {
        prompt: "2 + 2 = ",
        tokens: &[17, 488, 220, 17, 284, 220],
        expected_word: "4",
        expected_id: 19,
    },
];

fn manifest_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
}

/// The dense Qwen knot, or None to skip.
fn knot_path() -> Option<PathBuf> {
    if let Ok(p) = std::env::var("MONSTER_SWARM_QWEN_KNOT") {
        let pb = PathBuf::from(p);
        return pb.exists().then_some(pb);
    }
    let home = std::env::var("HOME").ok()?;
    let pb = PathBuf::from(home).join(".edgework/models/qwen-coder-7b.knot");
    pb.exists().then_some(pb)
}

/// The prebuilt `paris-probe-rknot` (the dense lm_head probe), or None.
fn probe_bin() -> Option<PathBuf> {
    if let Ok(p) = std::env::var("MONSTER_SWARM_PROBE_BIN") {
        let pb = PathBuf::from(p);
        return pb.exists().then_some(pb);
    }
    for profile in ["release", "debug"] {
        let p = manifest_dir().join(format!(
            "../distributed-inference/target/{profile}/paris-probe-rknot"
        ));
        if p.exists() {
            return Some(p);
        }
    }
    None
}

/// `tsx` for decoding token ids, or None.
fn tsx_bin() -> Option<PathBuf> {
    if let Ok(p) = std::env::var("MONSTER_SWARM_TSX") {
        let pb = PathBuf::from(p);
        return pb.exists().then_some(pb);
    }
    let pb = PathBuf::from("/opt/homebrew/bin/tsx");
    pb.exists().then_some(pb)
}

/// The Qwen tokenizer TS module + the gguf it loads its vocab from.
fn tokenizer_ts() -> PathBuf {
    if let Ok(p) = std::env::var("MONSTER_SWARM_TOKENIZER_TS") {
        return PathBuf::from(p);
    }
    manifest_dir().join("../distributed-inference-host/src/qwen-tokenizer.ts")
}

fn tokenizer_gguf() -> Option<PathBuf> {
    if let Ok(p) = std::env::var("MONSTER_SWARM_TOKENIZER_GGUF") {
        let pb = PathBuf::from(p);
        return pb.exists().then_some(pb);
    }
    let home = std::env::var("HOME").ok()?;
    let pb = PathBuf::from(home).join(
        "Library/CloudStorage/GoogleDrive-taylorbuley@gmail.com/My Drive/models/deepseek-r1-qwen3-8b-q4_k_m.gguf",
    );
    pb.exists().then_some(pb)
}

/// Decode a single Qwen token id to its string via the tsx tokenizer. Returns
/// None if the tokenizer toolchain (tsx + gguf + module) is unavailable, so the
/// caller can fall back to an id-only assertion.
fn decode_token(id: u64) -> Option<String> {
    let tsx = tsx_bin()?;
    let gguf = tokenizer_gguf()?;
    let module = tokenizer_ts();
    if !module.exists() {
        return None;
    }
    // tsx -e supports a top-level import; pass the id via process env so no
    // user-controlled string is interpolated into the program text.
    let program = format!(
        "import {{ loadQwenTokenizerFromGguf }} from {module:?}; \
         const t = loadQwenTokenizerFromGguf({gguf:?}); \
         process.stdout.write(t.decode([Number(process.env.TOK_ID)]));",
        module = module.display().to_string(),
        gguf = gguf.display().to_string(),
    );
    let out = Command::new(tsx)
        .arg("-e")
        .arg(&program)
        .env("TOK_ID", id.to_string())
        .output()
        .ok()?;
    if !out.status.success() {
        eprintln!(
            "[corpus] tokenizer decode failed (status {:?}): {}",
            out.status.code(),
            String::from_utf8_lossy(&out.stderr)
        );
        return None;
    }
    Some(String::from_utf8_lossy(&out.stdout).to_string())
}

/// Run `paris-probe-rknot` for one probe; return the argmax (rank-0) token id.
fn run_probe(probe_bin: &PathBuf, knot: &PathBuf, p: &Probe) -> Result<u64, String> {
    let tokens_csv = p
        .tokens
        .iter()
        .map(|t| t.to_string())
        .collect::<Vec<_>>()
        .join(",");
    let out = Command::new(probe_bin)
        .args([
            "--dense",
            &knot.display().to_string(),
            "--dense-only",
            "--tokens",
            &tokens_csv,
            "--expected",
            &p.expected_id.to_string(),
            "--top-k",
            "8",
        ])
        .output()
        .map_err(|e| format!("could not run probe: {e}"))?;
    let stdout = String::from_utf8_lossy(&out.stdout);
    // Parse the rank-0 line: "  rank 0: token_id=    19  logit=+20.527100".
    let argmax = stdout
        .lines()
        .find(|l| l.trim_start().starts_with("rank 0:"))
        .and_then(|l| l.split("token_id=").nth(1))
        .and_then(|rest| rest.split_whitespace().next())
        .and_then(|n| n.parse::<u64>().ok())
        .ok_or_else(|| {
            format!(
                "could not parse argmax from probe output:\n{stdout}\n--- stderr ---\n{}",
                String::from_utf8_lossy(&out.stderr)
            )
        })?;
    // The probe also exits 0 iff its argmax matches `--expected`; cross-check.
    if !out.status.success() {
        return Err(format!(
            "probe did not confirm expected id {} (argmax {argmax}, exit {:?})",
            p.expected_id,
            out.status.code()
        ));
    }
    Ok(argmax)
}

#[test]
fn corpus_completions_decode_to_expected_text() {
    // ---- gate: the cached knot + the prebuilt probe binary --------------
    let Some(knot) = knot_path() else {
        eprintln!("SKIP: no dense Qwen knot (set $MONSTER_SWARM_QWEN_KNOT or place ~/.edgework/models/qwen-coder-7b.knot)");
        return;
    };
    let Some(probe) = probe_bin() else {
        eprintln!("SKIP: paris-probe-rknot not built (set $MONSTER_SWARM_PROBE_BIN or build it in ../distributed-inference)");
        return;
    };

    // Can we render assertions as text? (tsx + tokenizer gguf present.)
    let text_mode = tsx_bin().is_some() && tokenizer_gguf().is_some() && tokenizer_ts().exists();
    if !text_mode {
        eprintln!("[corpus] tokenizer unavailable — asserting token ids only (text decode skipped)");
    }

    for p in CORPUS {
        let argmax = run_probe(&probe, &knot, p).unwrap_or_else(|e| {
            panic!("probe failed for {:?} (expected {:?}={}): {e}", p.prompt, p.expected_word, p.expected_id)
        });

        // The model's prediction, as text — the self-documenting assertion.
        if text_mode {
            let predicted = decode_token(argmax).unwrap_or_else(|| {
                panic!("could not decode predicted token {argmax} for {:?}", p.prompt)
            });
            eprintln!(
                "[corpus] {:?} -> {predicted:?} (token {argmax})  expected {:?} (token {})",
                p.prompt, p.expected_word, p.expected_id
            );
            assert_eq!(
                predicted, p.expected_word,
                "quality regression: {:?} completed to {predicted:?} (token {argmax}), expected {:?} (token {})",
                p.prompt, p.expected_word, p.expected_id
            );
        } else {
            eprintln!(
                "[corpus] {:?} -> token {argmax}  expected {:?} (token {})",
                p.prompt, p.expected_word, p.expected_id
            );
        }

        // Belt-and-suspenders: the id must match too (it's what `--expected`
        // confirmed, and what `expected_word` was verified to encode to).
        assert_eq!(
            argmax, p.expected_id,
            "quality regression: {:?} argmax token {argmax}, expected {} ({:?})",
            p.prompt, p.expected_id, p.expected_word
        );
    }
}
